{{ (() => {
  const searchData = $('Ambil Data Video').item.json.items;
  const statsData = $json.items;
  const messageText = $('Telegram Trigger').item.json.message.text;

  const keyword = messageText
    .replace('/trend ', '')
    .replace(/region:[a-zA-Z]{2}\s*$/i, '')
    .trim();

  const regionMatch = messageText.match(/region:([a-zA-Z]{2})\s*$/i);

  const regionName = regionMatch
    ? (() => {
        const inputRegion = regionMatch[1].toLowerCase();
        const regionNames = {
          id: 'Indonesia',
          us: 'Amerika Serikat',
          gb: 'Inggris',
          uk: 'Inggris',
          jp: 'Jepang',
          kr: 'Korea Selatan',
          au: 'Australia',
          ca: 'Kanada',
          de: 'Jerman',
          fr: 'Prancis',
          br: 'Brasil',
          mx: 'Meksiko',
          in: 'India',
          th: 'Thailand',
          my: 'Malaysia',
          sg: 'Singapura',
          ph: 'Filipina',
          vn: 'Vietnam'
        };
        return regionNames[inputRegion] || 'Global';
      })()
    : 'Global';

  function formatNumber(num) {
    if (!num) return 'N/A';
    const number = parseInt(num);
    if (number >= 1000000) return (number / 1000000).toFixed(1) + 'M';
    if (number >= 1000) return (number / 1000).toFixed(1) + 'K';
    return number.toLocaleString();
  }

  function getTimeSince(publishedAt) {
    const now = new Date();
    const published = new Date(publishedAt);
    const diffMs = now - published;
    const diffHours = Math.floor(diffMs / (1000 * 60 * 60));
    const diffDays = Math.floor(diffHours / 24);
    return diffDays > 0 ? `${diffDays} hari yang lalu` : `${diffHours} jam yang lalu`;
  }

  function calculateVPH(viewCount, publishedAt) {
    if (!viewCount) return 0;
    const now = new Date();
    const published = new Date(publishedAt);
    const diffHours = (now - published) / (1000 * 60 * 60);
    return Math.round(parseInt(viewCount) / diffHours);
  }

  function cleanText(text) {
    return text.replace(/[*_\[\]`]/g, '');
  }

  const videos = searchData.map(video => {
    const stats = statsData.find(stat => stat.id === video.id.videoId);
    return {
      ...video,
      statistics: stats ? stats.statistics : {}
    };
  });

  let message = `🔥 Trending Videos untuk: ${cleanText(keyword)}\n`;
  message += `🌍 Region: ${regionName}\n\n`;

  videos.forEach((video, index) => {
    const title = cleanText(video.snippet.title);
    const views = formatNumber(video.statistics.viewCount);
    const likes = formatNumber(video.statistics.likeCount);
    const comments = formatNumber(video.statistics.commentCount);
    const channel = cleanText(video.snippet.channelTitle);
    const timeSince = getTimeSince(video.snippet.publishedAt);
    const url = 'https://youtu.be/' + video.id.videoId;
    const vph = formatNumber(calculateVPH(video.statistics.viewCount, video.snippet.publishedAt));
    const isLive = video.snippet.liveBroadcastContent === 'live' ? '🔴 LIVE' : '';

    message += `${title}\n`;
    if (isLive) message += `${isLive}\n`;
    message += `👤 ${channel}\n`;
    message += `👁️ ${views} views • ⚡ ${vph}/jam\n`;
    message += `👍 ${likes} • 💬 ${comments}\n`;
    message += `🕒 ${timeSince}\n`;
    message += `${url}\n`;
    message += index < videos.length - 1 ? '---\n' : '\n';
  });

  message += `📊 Statistik Pencarian:\n`;
  message += `🎯 Keyword: ${cleanText(keyword)}\n`;
  message += `📈 Total hasil: ${videos.length} video teratas\n`;
  message += `⏰ Data diambil: ${new Date().toLocaleString('id-ID', { timeZone: 'Asia/Jakarta' })}\n\n`;

  return message;
})() }}

