{{ (() => {
  try {
    const channelData = $('Ambil Info Channel').item.json.items?.[0];
    const videosData = $('Ambil Data Video Channel').item.json.items || [];
    const statsData = $('Statistik Video Channel').item.json.items || [];
    const aiResponse = $('Analisis AI').item.json;

    if (!channelData) {
      return '❌ Error: Data channel tidak ditemukan';
    }

    function formatNumber(num) {
      if (!num) return 'N/A';
      const number = parseInt(num);
      if (number >= 1_000_000) return (number / 1_000_000).toFixed(1) + 'M';
      if (number >= 1_000) return (number / 1_000).toFixed(1) + 'K';
      return number.toLocaleString();
    }

    function getTimeSince(publishedAt) {
      const now = new Date();
      const published = new Date(publishedAt);
      const diffHours = Math.floor((now - published) / (1000 * 60 * 60));
      const diffDays = Math.floor(diffHours / 24);
      return diffDays > 0 ? `${diffDays} hari yang lalu` : `${diffHours} jam yang lalu`;
    }

    function calculateVPH(viewCount, publishedAt) {
      if (!viewCount) return 0;
      const now = new Date();
      const published = new Date(publishedAt);
      const diffHours = Math.max(1, (now - published) / (1000 * 60 * 60));
      return Math.round(parseInt(viewCount) / diffHours);
    }

    function decode(text) {
      if (!text) return '';
      return text
        .replace(/&amp;/g, '&')
        .replace(/&lt;/g, '<')
        .replace(/&gt;/g, '>')
        .replace(/&quot;/g, '"')
        .replace(/&#039;/g, "'")
        .replace(/&nbsp;/g, ' ');
    }

    const aiText = decode(aiResponse?.candidates?.[0]?.content?.parts?.[0]?.text || 'Tidak tersedia');

    const statsMap = Object.fromEntries(statsData.map(stat => [stat.id, stat.statistics]));

    const videosWithStats = videosData.map(video => ({
      ...video,
      statistics: statsMap[video.id.videoId] || {}
    }));

    const topVideos = [...videosWithStats]
      .sort((a, b) => parseInt(b.statistics?.viewCount || 0) - parseInt(a.statistics?.viewCount || 0))
      .slice(0, 3);

    const recentVideos = videosWithStats.slice(0, 5);

    const createdDate = new Date(channelData.snippet?.publishedAt);
    const avgViews = formatNumber(
      videosWithStats.reduce((sum, v) => sum + parseInt(v.statistics?.viewCount || 0), 0) / videosWithStats.length || 0
    );

    let message = '*📊 ANALISIS CHANNEL*\n\n';
    message += `*▶️ ${decode(channelData.snippet?.title || 'Unknown')}*\n`;
    message += `👥 ${formatNumber(channelData.statistics?.subscriberCount)} subscribers\n`;
    message += `🎬 ${formatNumber(channelData.statistics?.videoCount)} total videos\n`;
    message += `👁️ ${formatNumber(channelData.statistics?.viewCount)} total views\n`;
    message += `📅 Dibuat: ${createdDate.toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' })}\n`;
    message += `📈 Avg views: ${avgViews}/video\n\n`;
    message += '*🤖 ANALISA AI:*\n';
    message += aiText + '\n\n';
    message += '---\n\n';

    message += '*🏆 TOP 3 VIDEO TERBAIK:*\n';
    topVideos.forEach(v => {
      const title = decode(v.snippet?.title);
      const url = `https://youtu.be/${v.id.videoId}`;
      message += `[${title}](${url})\n`;
      message += `👁️ ${formatNumber(v.statistics?.viewCount)} • 👍 ${formatNumber(v.statistics?.likeCount)}\n\n`;
    });

    message += '---\n\n';
    message += '*🎬 5 VIDEO TERBARU:*\n';
    recentVideos.forEach(v => {
      const title = decode(v.snippet?.title);
      const url = `https://youtu.be/${v.id.videoId}`;
      const views = formatNumber(v.statistics?.viewCount);
      const likes = formatNumber(v.statistics?.likeCount);
      const comments = formatNumber(v.statistics?.commentCount);
      const vph = formatNumber(calculateVPH(v.statistics?.viewCount, v.snippet?.publishedAt));
      const since = getTimeSince(v.snippet?.publishedAt);

      message += `[${title}](${url})\n`;
      message += `👁️ ${views} • 👍 ${likes} • 💬 ${comments}\n`;
      message += `⚡ ${vph}/jam • 🕒 ${since}\n\n`;
    });

    message += '---\n';
    message += `⏰ ${new Date().toLocaleString('id-ID', { timeZone: 'Asia/Jakarta' })}`;

    return message;
  } catch (err) {
    return '❌ Error: Gagal memproses analisis channel.';
  }
})() }}

